};

struct No* inserir(struct No* raiz, int v) {
    if (!raiz) {
        struct No* n = malloc(sizeof(*n));
        n->valor = v; n->esq = n->dir = NULL;
        return n;
    }
    if (v < raiz->valor) raiz->esq = inserir(raiz->esq, v);
    else if (v > raiz->valor) raiz->dir = inserir(raiz->dir, v);
    return raiz;
}

